final:
module top_module( A, B, Ci, S, Co );input A, B, Ci;
  output S, Co;

  wire   sum_xor, n2, n3;

  // Calculate sum (S)
  assign sum_xor = A ^ B;    // XOR
  assign S = sum_xor ^ Ci;   // XOR with carry-in

  // Calculate carry out (Co)
  assign n2 = A & B;    // AND
  assign n3 = sum_xor & Ci;  // AND with carry-in
  assign Co = n2 | n3;  // OR for final carry out

endmodule
